function libraryKey(kind){var user=(atlasSession.username||atlasSession.role||'local').replace(/[^a-z0-9_.-]/gi,'_');return'code_atlas:'+user+':'+kind}
function libraryItems(kind){try{return JSON.parse(localStorage.getItem(libraryKey(kind))||'[]')}catch(e){return[]}}
function normalizeLibraryItem(kind,item){item=item||{};var stable=item.stable_id||item.id||item.dossier_id||item.chain_id||String(Date.now()),href=item.href||item.view_params&&item.view_params.href||'#';return{object_type:item.object_type||kind,stable_id:stable,id:stable,display_title:item.display_title||item.label||item.title||stable,view_params:item.view_params||{href:href},saved_at:item.saved_at||new Date().toISOString()}}
function saveLibraryItem(kind,item){item=normalizeLibraryItem(kind,item);var items=libraryItems(kind).filter(function(x){return(x.stable_id||x.id)!==item.stable_id});items.unshift(item);localStorage.setItem(libraryKey(kind),JSON.stringify(items.slice(0,80)));showToast('已保存到当前浏览器','success')}
function deleteLibraryItem(kind,id){localStorage.setItem(libraryKey(kind),JSON.stringify(libraryItems(kind).filter(function(x){return(x.stable_id||x.id)!==id})));libraryWorkspace()}
function renderLibraryList(kind,limit){var items=libraryItems(kind).slice(0,limit||50);return'<div class="list">'+(items.map(function(x){var href=(x.view_params&&x.view_params.href)||x.href||'#',id=x.stable_id||x.id;return'<div class="card library-item"><h3>'+esc(x.display_title||x.label||id)+'</h3><p class="meta">'+esc(x.object_type||kind)+' · 保存在当前浏览器 · '+esc(x.saved_at||'')+'</p><div class="toolbar"><a class="button-sm" href="'+esc(href)+'">打开</a><button class="button-sm" onclick="deleteLibraryItem(\''+kind+'\',\''+esc(id)+'\')">删除</button></div></div>'}).join('')||'<div class="empty">暂无记录。保存在当前浏览器，不会跨设备同步。</div>')+'</div>'}
function rememberRecent(item){saveLibraryItem('recent',item)}
