function annotationValues(a){var v=Object.assign({},a&&a.structured_fields||{});if(a&&a.final_label)v.final_label=a.final_label;if(a&&a.notes)v.notes=a.notes;return v}
function visibleField(field,values){var r=field.visible_when;if(!r)return true;var v=values[r.field];if(r.in)return r.in.indexOf(v)>=0;return v===r.equals}
function renderSchemaField(field,values,errors){if(!visibleField(field,values))return"";var id="ann-field-"+field.field_id,v=values[field.field_id];var req=field.required?' <span class="badge warn">required</span>':'',err=errors&&errors[field.field_id]?'<p class="error field-error">'+esc(errors[field.field_id])+'</p>':'';var label='<label for="'+id+'">'+esc(field.label||field.field_id)+req+'</label>';var help=field.help_text||field.description||'',helpHtml=help?'<p class="meta">'+esc(help)+'</p>':'';var opts=field.allowed_values||[];if(field.type==="single_choice")return'<div class="field-control schema-field" data-field="'+esc(field.field_id)+'">'+label+'<select id="'+id+'" data-schema-field="'+esc(field.field_id)+'"><option value=""></option>'+opts.map(function(o){return'<option value="'+esc(o)+'"'+(v===o?' selected':'')+'>'+esc(o)+'</option>'}).join('')+'</select>'+helpHtml+err+'</div>';if(field.type==="multi_choice"||field.type==="context_slot_set"||field.type==="ranked_list"||field.type==="entity_reference"){var vals=Array.isArray(v)?v:[];return'<div class="field-control schema-field" data-field="'+esc(field.field_id)+'">'+label+'<div class="checkbox-grid">'+opts.map(function(o){return'<label><input type="checkbox" data-schema-field="'+esc(field.field_id)+'" value="'+esc(o)+'" '+(vals.indexOf(o)>=0?'checked':'')+'> '+esc(o)+'</label>'}).join('')+'</div>'+helpHtml+err+'</div>'}if(field.type==="boolean")return'<div class="field-control schema-field" data-field="'+esc(field.field_id)+'">'+label+'<select id="'+id+'" data-schema-field="'+esc(field.field_id)+'"><option value=""></option><option value="true"'+(v===true?' selected':'')+'>Yes</option><option value="false"'+(v===false?' selected':'')+'>No</option></select>'+helpHtml+err+'</div>';if(field.type==="integer"||field.type==="number"||field.type==="likert_1_5"){var min=field.type==="likert_1_5"?' min="1" max="5"':'';return'<div class="field-control schema-field" data-field="'+esc(field.field_id)+'">'+label+'<input id="'+id+'" data-schema-field="'+esc(field.field_id)+'" type="number"'+min+' value="'+esc(v||'')+'">'+helpHtml+err+'</div>'}if(field.type==="long_text")return'<div class="field-control schema-field field-control-full" data-field="'+esc(field.field_id)+'">'+label+'<textarea id="'+id+'" data-schema-field="'+esc(field.field_id)+'" rows="3">'+esc(v||'')+'</textarea>'+helpHtml+err+'</div>';return'<div class="field-control schema-field" data-field="'+esc(field.field_id)+'">'+label+'<input id="'+id+'" data-schema-field="'+esc(field.field_id)+'" value="'+esc(v||'')+'">'+helpHtml+err+'</div>'}
function collectSchemaFields(){var values={};document.querySelectorAll('[data-schema-field]').forEach(function(el){var key=el.dataset.schemaField;if(el.type==="checkbox"){if(!values[key])values[key]=[];if(el.checked)values[key].push(el.value);return}if(el.tagName==="SELECT"&&el.value==="true")values[key]=true;else if(el.tagName==="SELECT"&&el.value==="false")values[key]=false;else if(el.type==="number"&&el.value!=="")values[key]=Number(el.value);else if(el.value!=="")values[key]=el.value});if(_crLabel)values.final_label=_crLabel;var notes=document.querySelector('#ann-notes');if(notes&&notes.value)values.notes=notes.value;return values}
function wireSchemaVisibility(fields){document.querySelectorAll('[data-schema-field]').forEach(function(el){el.addEventListener('change',function(){var values=collectSchemaFields();fields.forEach(function(f){var box=document.querySelector('.schema-field[data-field="'+CSS.escape(f.field_id)+'"]');if(box)box.style.display=visibleField(f,values)?'':'none'})})})}
async function openReviewItem(encoded){var seq=++_reviewRequestSeq,x=await api('/api/review-item/'+encoded);if(seq!==_reviewRequestSeq)return;var a=x.annotation||{},form=x.form_definition||{},values=annotationValues(a);_crItem=x;_crAnnot=a;_crLabel=a.final_label||values.final_label||'';_crDisposition=a.review_disposition||'submitted';_crDirty=false;document.querySelectorAll('.review-queue-item').forEach(function(el){el.classList.toggle('selected-item',el.id==='queue-'+x.review_item_id)});var panel=document.querySelector('#review-detail-panel');if(form.configured===false){panel.innerHTML='<div class="review-detail-card"><div class="error"><h3>尚未配置正式标注 Schema</h3><p>Production 提交已禁用。Owner 可在 test namespace 查看原始对象。</p></div>'+renderDeveloperDetails(x,"Review item raw / debug")+'</div>';return}var labels=quickLabels(x.item_type),fields=form.fields||[];panel.innerHTML='<div class="review-detail-card"><div class="review-section"><span class="badge type">'+esc(x.item_type)+'</span><span class="badge">'+esc(form.schema_id||x.schema_id||'schema missing')+'</span><span class="badge">'+esc(form.schema_version||x.schema_version||'')+'</span><span class="badge type reviewer-only">'+esc(x.case_id||'')+'</span><span id="review-save-badge" class="badge '+(a.final_label||a.review_disposition?'':'warn')+'">'+(a.final_label||a.review_disposition?'Saved: '+esc(a.final_label||a.review_disposition):'Unsaved')+'</span><p class="badge warn review-disclaimer">Manual review labels assess extraction and triage quality. They do not constitute biological validation.</p><h3>'+esc(x.subject||x.paper_title||x.review_item_id||'Review item')+'</h3><p class="meta">Project: '+esc((x.evaluation_project&&x.evaluation_project.name)||x.project_id||'')+' · Guideline: '+esc(form.instructions_version||x.instructions_version||'')+'</p><div class="extraction-grid"><div class="extraction-field"><strong>Subject</strong> '+esc(x.subject||'-')+'</div><div class="extraction-field"><strong>Relation</strong> '+esc(x.relation||'-')+'</div><div class="extraction-field"><strong>Object</strong> '+esc(x.object||'-')+'</div><div class="extraction-field"><strong>Direction</strong> '+esc(x.direction||'-')+'</div><div class="extraction-field"><strong>Context</strong> '+esc(x.context||x.context_text||'-')+'</div></div></div><div class="review-section"><h5 class="review-section-title">Evidence</h5><div class="evidence-box"><blockquote>'+esc(x.evidence_sentence||x.claim_text||x.rejection_reason||'No evidence preview')+'</blockquote><p class="meta">'+esc(x.paper_title||'')+' · PMID '+esc(x.pmid||'-')+' · PMCID '+esc(x.pmcid||'-')+'</p></div></div><div class="review-section"><h5 class="review-section-title">'+esc(form.title||'Annotation')+'</h5><div id="review-quick-labels" class="judgment-button-row">'+labels.map(function(pair){var active=(pair[1]==='SKIP'?a.review_disposition==='skipped':_crLabel===pair[1]);return'<button data-label="'+pair[1]+'" class="review-choice'+(active?' active':'')+'" onclick="chooseReviewLabel(\''+pair[1]+'\',this)">'+pair[0]+'</button>'}).join('')+'</div><div class="secondary-field-grid schema-field-grid">'+fields.filter(function(f){return f.field_id!=="final_label"&&f.field_id!=="notes"}).map(function(f){return renderSchemaField(f,values,{})}).join('')+'</div></div>'+renderDeveloperDetails(x,"Review item raw / debug")+'<div class="review-section"><div class="review-actions"><div class="field-control field-control-full"><label>Notes</label><textarea id="ann-notes" data-schema-field="notes" rows="3" placeholder="Optional notes">'+esc(a.notes||values.notes||'')+'</textarea></div><button class="button-sm" onclick="markReviewRevisit(\''+encoded+'\')">标记需要复查</button><button class="button review-save-btn" onclick="saveReviewAnnotation(\''+encoded+'\')">Save Annotation</button><div id="review-save-message"></div></div></div></div>';wireSchemaVisibility(fields);var draftKey=libraryKey('draft:'+x.review_item_id),draft=localStorage.getItem(draftKey),notes=document.querySelector('#ann-notes');if(notes&&draft&&!a.notes)notes.value=draft;if(notes)notes.oninput=function(){localStorage.setItem(draftKey,notes.value)}}
async function saveReviewAnnotation(encoded){if(!_crLabel&&_crDisposition!=='skipped'){document.querySelector('#review-save-message').innerHTML='<span class="error">Select a primary judgment label first.</span>';return}var body={final_label:_crLabel,review_disposition:_crDisposition,uncertainty_reason:_crDisposition==='skipped'?'reviewer_unfamiliar':'',structured_fields:collectSchemaFields(),notes:document.querySelector('#ann-notes')?document.querySelector('#ann-notes').value:''};var saveBtn=document.querySelector('.review-save-btn');if(saveBtn){saveBtn.disabled=true;saveBtn.textContent='Saving...'}try{var result=await apiPost('/api/annotation/'+encoded,body);_crDirty=false;_lastSubmittedReview={encoded:encoded,item_id:result.review_item_id,label:result.final_label||result.review_disposition};localStorage.removeItem(libraryKey('draft:'+result.review_item_id));var badge=document.querySelector('#review-save-badge');if(badge){badge.textContent='Saved: '+(result.final_label||result.review_disposition);badge.className='badge'}document.querySelector('#review-save-message').innerHTML='<span class="badge saved-indicator">Saved</span>';showToast('Annotation saved','success');markReviewItemDone(result);updateReviewMetrics();advanceReviewAfterSave(result.review_item_id)}catch(e){var msg=e.message;if(e.field_errors)msg+=' '+JSON.stringify(e.field_errors);document.querySelector('#review-save-message').innerHTML='<span class="error">'+esc(msg)+'</span>';showToast('Save failed: '+msg,'error')}finally{if(saveBtn){saveBtn.disabled=false;saveBtn.textContent='Save Annotation'}}}
async function ownerWorkspace(){var p=location.pathname.replace(/^\/owner\/?/,'')||'overview';title('Owner Control Center','正式评估平台总控：用户、项目、任务、仲裁、Gold、指标、质量、审计和导出。');var tabs=['overview','people','projects','assignments','adjudication','gold','evaluation','quality','audit','exports'];W.innerHTML+='<div class="toolbar">'+tabs.map(function(t){return'<a class="button-sm '+(p===t?'active':'')+'" href="/owner/'+t+'">'+esc(t)+'</a>'}).join('')+'</div>';if(p==='people'){var people=await api('/api/owner/people');W.innerHTML+='<div class="card"><table><thead><tr><th>username</th><th>display</th><th>role</th><th>enabled</th><th>assigned</th><th>submitted</th><th>skipped</th><th>revisit</th></tr></thead><tbody>'+asItems(people).map(function(x){return'<tr><td>'+esc(x.username)+'</td><td>'+esc(x.display_name)+'</td><td>'+esc(x.role)+'</td><td>'+esc(x.enabled)+'</td><td>'+esc(x.assigned||0)+'</td><td>'+esc(x.submitted||0)+'</td><td>'+esc(x.skipped||0)+'</td><td>'+esc(x.revisit||0)+'</td></tr>'}).join('')+'</tbody></table></div>'+renderDeveloperDetails(people,"People raw");return}if(p==='quality'){var q=await api('/api/owner/quality');W.innerHTML+='<div class="list">'+asItems(q).map(function(x){return'<div class="card"><span class="badge warn">'+esc(x.warning||x.type||'warning')+'</span><pre>'+esc(JSON.stringify(x,null,2))+'</pre></div>'}).join('')+'</div>';return}if(p==='audit'){var au=await api('/api/owner/audit');W.innerHTML+='<div class="card"><pre>'+esc(JSON.stringify(au,null,2))+'</pre></div>';return}if(p==='gold'){W.innerHTML+='<div class="card"><h2>Gold</h2><p class="meta">Use the API controls after selecting a project. Freeze will create Gold Dataset vN and keep candidate revisions separate.</p></div>';return}if(p==='evaluation'||p==='exports'||p==='projects'||p==='assignments'||p==='adjudication'){W.innerHTML+='<div class="card"><h2>'+esc(p)+'</h2><p class="meta">Operational API is available; this panel shows missing status instead of placeholder numbers until a project is selected.</p></div>';return}var d=await api('/api/owner/overview');W.innerHTML+='<div class="grid">'+[['正式用户数',d.formal_user_count],['活跃 reviewer',d.active_reviewer_count],['production annotations',d.production_annotations],['pilot annotations',d.pilot_annotations],['test annotations',d.test_annotations],['calibration annotations',d.calibration_annotations],['任务分配',d.assignment_count],['Review items',d.review_item_count],['Frozen Gold',d.frozen_gold_count],['Audit events',d.audit_event_count]].map(function(x){return'<div class="card metric"><strong>'+esc(x[1]===null?'不可计算':x[1])+'</strong>'+esc(x[0])+'</div>'}).join('')+'</div><h2>Quality Warnings</h2><div class="card"><pre>'+esc(JSON.stringify(d.data_quality_warnings||[],null,2))+'</pre></div>'+renderDeveloperDetails(d,"Owner overview raw")}
async function evaluationWorkspace(){var p=location.pathname.replace(/^\/evaluation\/?/,'')||'home';title('Evaluation Center','正式评估只使用 production + frozen Gold Dataset version。缺失依赖显示 missing status，不显示伪造的 0。');var tabs=['home','protocol','readiness','agreement','conflicts','contexts','components','hypotheses','forward','efficiency','runs','exports'];W.innerHTML+='<div class="toolbar">'+tabs.map(function(t){return'<a class="button-sm '+(p===t?'active':'')+'" href="/evaluation/'+t+'">'+esc(t)+'</a>'}).join('')+'</div><div class="grid"><div class="card metric"><strong>missing</strong>Conflict Macro-F1</div><div class="card metric"><strong>missing</strong>Context Recall@3 / Jaccard</div><div class="card metric"><strong>missing</strong>Novel-and-Future-Supported@5</div></div><div class="card"><h2>'+esc(p)+'</h2><p class="meta">Select a production project and frozen Gold Dataset version through Owner controls or API to compute readiness and metric runs.</p></div>'}
