document.addEventListener('keydown',function(e){if(['INPUT','TEXTAREA','SELECT'].indexOf(document.activeElement.tagName)>=0)return;var map={v:'VALID',p:'PARTIAL',i:'INVALID',u:'UNCLEAR'};if(map[e.key.toLowerCase()]&&document.querySelector('#review-quick-labels')){var val=map[e.key.toLowerCase()],btn=document.querySelector('#review-quick-labels .review-choice[data-label="'+val+'"]');if(btn)chooseReviewLabel(val,btn)}if(e.key.toLowerCase()==='s'&&document.querySelector('.review-save-btn')){document.querySelector('.review-save-btn').click()}});

