async function route(){try{var p=decodeURIComponent(location.pathname),m;if(p==='/'||p==='/discover'||p==='/problems')return discoverHome();if(p==='/search')return searchView();if(p==='/library')return libraryWorkspace();if(p==='/cases')return caseList();if((m=p.match(/^\/case\/(.+)$/)))return caseDetail(m[1]);if(p==='/evidence')return evidenceWorkspace();if((m=p.match(/^\/dossier\/(.+)$/)))return dossierView(m[1]);if(p==='/entities')return entities();if((m=p.match(/^\/entity\/(.+)$/)))return entityDetail(m[1]);if(p==='/chains')return chains();if((m=p.match(/^\/chain\/(.+)$/)))return chainPage(m[1]);if(p==='/triples')return evidenceWorkspace();if((m=p.match(/^\/triple\/(.+)$/)))return dossierView(m[1]);if(p==='/graph')return graphView();if(p==='/conflicts')return conflicts();if(p==='/review')return review(false);if(p==='/progress')return progressWorkspace();if(p==='/metrics')return review(true);if(p==='/dev'||p==='/console')return devWorkspace();if(p==='/owner'||p.indexOf('/owner/')===0)return ownerWorkspace();if(p==='/evaluation'||p.indexOf('/evaluation/')===0)return evaluationWorkspace();if(p==='/help')return helpWorkspace();return discoverHome()}catch(e){console.error('Route error:',e);W.innerHTML='<div class="error"><h2>Unable to load view</h2><p>'+esc(e.message||'Unknown error')+'</p><p class="muted">Try refreshing the page. If the problem persists, the data source may be unavailable.</p></div>'}}

