document.addEventListener('click',function(e){var copyEl=e.target.closest('[data-copy-text]');if(copyEl){e.preventDefault();e.stopPropagation();copyTextToClipboard(copyEl.dataset.copyText||"",copyEl);return}var saveEl=e.target.closest('[data-library-save]');if(saveEl){e.preventDefault();saveLibraryItem(saveEl.dataset.librarySave,{object_type:saveEl.dataset.librarySave,stable_id:saveEl.dataset.libraryId,display_title:saveEl.dataset.libraryLabel,view_params:{href:'/dossier/'+encodeURIComponent(saveEl.dataset.libraryId)}});return}var graphEdgeEl=e.target.closest('[data-graph-edge-id]');if(graphEdgeEl){e.preventDefault();selectGraphEdge(graphEdgeEl.dataset.graphEdgeId);return}var graphNodeEl=e.target.closest('[data-graph-node-id][data-graph-neighborhood]');if(graphNodeEl){e.preventDefault();loadGraphNeighborhood(graphNodeEl.dataset.graphNodeId,graphNodeEl.dataset.graphNeighborhood);return}graphNodeEl=e.target.closest('[data-graph-node-id]');if(graphNodeEl){e.preventDefault();selectGraphNode(graphNodeEl.dataset.graphNodeId);return}var pathEl=e.target.closest('[data-path-source][data-path-target]');if(pathEl){e.preventDefault();prefillGraphPath(pathEl.dataset.pathSource,pathEl.dataset.pathTarget);return}var chainEl=e.target.closest('[data-chain-id]');if(chainEl){e.preventDefault();openChain(chainEl.dataset.chainId);return}var tripleEl=e.target.closest('[data-triple-id]');if(tripleEl){e.preventDefault();location.href='/dossier/'+encodeURIComponent(tripleEl.dataset.tripleId);return}});

async function boot(){initModeSwitch();var errors=[];try{atlasSession=await api('/api/session');configureSessionCapabilities(atlasSession)}catch(e){errors.push('Session: '+e.message);atlasSession={csrf_token:'',allowed_workspaces:["discover","library"],debug_access:false};configureSessionCapabilities(atlasSession)}var userEl=document.querySelector('#current-user');if(atlasSession.user){userEl.innerHTML='<span>'+esc(atlasSession.user.display_name)+'</span> <button class="badge logout-button" type="button" onclick="atlasLogout()">Logout</button>'}else{userEl.innerHTML='<span class="muted">Local no-auth mode</span>'};try{var c=await api('/api/cases');cases=c.items;document.querySelector('#case-select').innerHTML+=[...cases].map(function(x){return'<option value="'+esc(x.case_id)+'">'+esc(x.case_id)+'</option>'}).join('')}catch(e){errors.push('Cases: '+e.message);cases=[]};document.querySelector('#case-select').onchange=function(e){if(e.target.value)location.href='/case/'+encodeURIComponent(e.target.value)};document.querySelector('#global-search').placeholder='搜索药物、基因、蛋白、通路、疾病、研究问题或 PMID';document.querySelector('#global-search').onkeydown=function(e){if(e.key==='Enter')location.href='/search?q='+encodeURIComponent(e.target.value)};document.addEventListener('keydown',function(e){if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='k'){e.preventDefault();document.querySelector('#global-search').focus()}});if(errors.length>0){var banner=document.createElement('div');banner.className='error-banner';banner.innerHTML='<strong>Startup warnings:</strong> '+errors.map(esc).join('; ')+' <button class=\"button-sm\" onclick=\"this.parentElement.remove()\">Dismiss</button>';document.querySelector('header').after(banner)};await route()}boot().catch(function(e){W.innerHTML='<div class="error">'+esc(e.message)+'</div>'});
